import { z } from 'zod';
import type { Timeline, TimelineItem, TimelineContext } from './Timeline.js';
import type { PrecisionClock } from '@psyforge/timing';
import type { Scheduler, createScheduler } from '@psyforge/scheduling';
import type { DeviceManager } from '@psyforge/devices';
import { sanitizeColorValue, sanitizeCursorValue } from '../utils/security.js';
import { ConsentManager, type ConsentOptions, type ConsentResult } from '../utils/consent.js';

export interface ExperimentMetadata {
  title: string;
  description?: string;
  version: string;
  author?: string;
  institution?: string;
  doi?: string;
  license?: string;
  tags?: string[];
  created: number;
  modified: number;
  psychoforgeVersion: string;
}

export interface ExperimentData {
  participantId?: string;
  sessionId: string;
  startTime: number;
  endTime?: number;
  responses: unknown[];
  collectedData: unknown[];
  metadata: Record<string, unknown>;
  consent?: ConsentResult;
}

export interface ExperimentOptions {
  metadata?: Partial<ExperimentMetadata>;
  preloadAssets?: boolean;
  fullScreen?: boolean;
  cursor?: string;
  backgroundColor?: string;
  consent?: ConsentOptions;
  requireConsent?: boolean;
  onStart?: (context: TimelineContext) => void;
  onComplete?: (data: ExperimentData) => void;
  onError?: (error: Error, context?: TimelineContext) => void;
  onConsentDenied?: (result: ConsentResult) => void;
}

export class Experiment {
  private timelines: Timeline[] = [];
  private metadata: ExperimentMetadata;
  private options: ExperimentOptions;
  private clock?: PrecisionClock;
  private scheduler?: Scheduler;
  private deviceManager?: DeviceManager;
  private experimentData?: ExperimentData;
  private isRunning = false;
  private consentManager: ConsentManager;

  constructor(id: string, options: ExperimentOptions = {}) {
    this.options = options;
    this.consentManager = ConsentManager.getInstance();

    // Initialize metadata with defaults
    this.metadata = {
      title: options.metadata?.title || 'Untitled Experiment',
      description: options.metadata?.description,
      version: options.metadata?.version || '1.0.0',
      author: options.metadata?.author,
      institution: options.metadata?.institution,
      doi: options.metadata?.doi,
      license: options.metadata?.license || 'MIT',
      tags: options.metadata?.tags || [],
      created: options.metadata?.created || Date.now(),
      modified: Date.now(),
      psychoforgeVersion: '0.1.0', // This should come from package.json
      ...options.metadata,
    };
  }

  title(experimentTitle: string): this {
    this.metadata.title = experimentTitle;
    this.metadata.modified = Date.now();
    return this;
  }

  description(desc: string): this {
    this.metadata.description = desc;
    this.metadata.modified = Date.now();
    return this;
  }

  version(ver: string): this {
    this.metadata.version = ver;
    this.metadata.modified = Date.now();
    return this;
  }

  author(authorName: string): this {
    this.metadata.author = authorName;
    this.metadata.modified = Date.now();
    return this;
  }

  institution(inst: string): this {
    this.metadata.institution = inst;
    this.metadata.modified = Date.now();
    return this;
  }

  doi(doiString: string): this {
    this.metadata.doi = doiString;
    this.metadata.modified = Date.now();
    return this;
  }

  license(licenseType: string): this {
    this.metadata.license = licenseType;
    this.metadata.modified = Date.now();
    return this;
  }

  tags(tagList: string[]): this {
    this.metadata.tags = tagList;
    this.metadata.modified = Date.now();
    return this;
  }

  timeline(timelineList: Timeline[]): this {
    this.timelines = timelineList;
    this.metadata.modified = Date.now();
    return this;
  }

  addTimeline(timeline: Timeline): this {
    this.timelines.push(timeline);
    this.metadata.modified = Date.now();
    return this;
  }

  preloadAssets(shouldPreload: boolean): this {
    this.options.preloadAssets = shouldPreload;
    return this;
  }

  fullScreen(shouldFullScreen: boolean): this {
    this.options.fullScreen = shouldFullScreen;
    return this;
  }

  cursor(cursorType: string): this {
    this.options.cursor = cursorType;
    return this;
  }

  backgroundColor(color: string): this {
    this.options.backgroundColor = color;
    return this;
  }

  onStart(callback: (context: TimelineContext) => void): this {
    this.options.onStart = callback;
    return this;
  }

  onComplete(callback: (data: ExperimentData) => void): this {
    this.options.onComplete = callback;
    return this;
  }

  onError(callback: (error: Error, context?: TimelineContext) => void): this {
    this.options.onError = callback;
    return this;
  }

  consent(consentOptions: ConsentOptions): this {
    this.options.consent = consentOptions;
    return this;
  }

  requireConsent(required: boolean = true): this {
    this.options.requireConsent = required;
    return this;
  }

  onConsentDenied(callback: (result: ConsentResult) => void): this {
    this.options.onConsentDenied = callback;
    return this;
  }

  private async initializeEnvironment(): Promise<void> {
    // Set background color with sanitization
    if (this.options.backgroundColor) {
      const sanitizedColor = sanitizeColorValue(this.options.backgroundColor);
      if (sanitizedColor) {
        document.body.style.backgroundColor = sanitizedColor;
      }
    }

    // Set cursor with sanitization
    if (this.options.cursor) {
      const sanitizedCursor = sanitizeCursorValue(this.options.cursor);
      if (sanitizedCursor) {
        document.body.style.cursor = sanitizedCursor;
      }
    }

    // Request fullscreen if specified
    if (this.options.fullScreen) {
      try {
        await document.documentElement.requestFullscreen();
      } catch (error) {
        console.warn('Fullscreen request failed:', error);
      }
    }

    // Preload assets if specified
    if (this.options.preloadAssets) {
      await this.preloadExperimentAssets();
    }
  }

  private async preloadExperimentAssets(): Promise<void> {
    // This would scan timelines for media assets and preload them
    // For now, this is a placeholder implementation
    console.log('Preloading experiment assets...');
  }

  private createContext(): TimelineContext {
    if (!this.clock || !this.scheduler) {
      throw new Error('Experiment not properly initialized');
    }

    return {
      clock: this.clock,
      scheduler: this.scheduler,
      data: {
        participantId: this.experimentData?.participantId,
        sessionId: this.experimentData?.sessionId,
        responses: [],
        collectedData: [],
      },
    };
  }

  async run(participantId?: string): Promise<ExperimentData> {
    if (this.isRunning) {
      throw new Error('Experiment is already running');
    }

    this.isRunning = true;

    try {
      // Initialize timing and scheduling systems
      const { PrecisionClock } = await import('@psyforge/timing');
      const { createScheduler } = await import('@psyforge/scheduling');

      this.clock = new PrecisionClock();
      this.scheduler = createScheduler(this.clock);

      // Initialize experiment data
      this.experimentData = {
        participantId,
        sessionId: crypto.randomUUID(),
        startTime: this.clock.now(),
        responses: [],
        collectedData: [],
        metadata: {
          experimentMetadata: this.metadata,
          userAgent: navigator.userAgent,
          screenResolution: `${screen.width}x${screen.height}`,
          viewportSize: `${window.innerWidth}x${window.innerHeight}`,
        },
      };

      // Initialize environment
      await this.initializeEnvironment();

      // Create execution context
      const context = this.createContext();

      // Call onStart callback
      if (this.options.onStart) {
        this.options.onStart(context);
      }

      // Execute all timelines
      for (const timeline of this.timelines) {
        await timeline.execute(context);
      }

      // Finalize experiment data
      this.experimentData.endTime = this.clock.now();
      this.experimentData.responses = context.data.responses as unknown[] || [];
      this.experimentData.collectedData = context.data.collectedData as unknown[] || [];

      // Call onComplete callback
      if (this.options.onComplete) {
        this.options.onComplete(this.experimentData);
      }

      return this.experimentData;

    } catch (error) {
      const err = error as Error;

      // Call onError callback
      if (this.options.onError) {
        this.options.onError(err, this.createContext());
      }

      throw err;
    } finally {
      this.isRunning = false;

      // Clean up environment
      if (this.options.fullScreen && document.fullscreenElement) {
        await document.exitFullscreen();
      }
    }
  }

  stop(): void {
    if (!this.isRunning) {
      return;
    }

    this.isRunning = false;

    // This would stop all running timelines and clean up
    // For now, this is a basic implementation
    console.log('Stopping experiment...');
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    // Check metadata requirements
    if (!this.metadata.title.trim()) {
      errors.push('Experiment title is required');
    }

    if (!this.metadata.version.trim()) {
      errors.push('Experiment version is required');
    }

    // Check timeline requirements
    if (this.timelines.length === 0) {
      errors.push('Experiment must have at least one timeline');
    }

    // Validate each timeline
    for (const timeline of this.timelines) {
      if (timeline.getItems().length === 0) {
        errors.push(`Timeline '${timeline.id}' is empty`);
      }
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }

  getMetadata(): ExperimentMetadata {
    return { ...this.metadata };
  }

  getTimelines(): Timeline[] {
    return [...this.timelines];
  }

  getExperimentData(): ExperimentData | undefined {
    return this.experimentData ? { ...this.experimentData } : undefined;
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'Experiment',
      metadata: this.metadata,
      options: {
        ...this.options,
        // Remove non-serializable callbacks
        onStart: undefined,
        onComplete: undefined,
        onError: undefined,
      },
      timelines: this.timelines.map(timeline => timeline.serialize()),
    };
  }

  static deserialize(data: Record<string, unknown>): Experiment {
    const schema = z.object({
      metadata: z.object({
        title: z.string(),
        description: z.string().optional(),
        version: z.string(),
        author: z.string().optional(),
        institution: z.string().optional(),
        doi: z.string().optional(),
        license: z.string().optional(),
        tags: z.array(z.string()).optional(),
        created: z.number(),
        modified: z.number(),
        psychoforgeVersion: z.string(),
      }),
      options: z.object({
        preloadAssets: z.boolean().optional(),
        fullScreen: z.boolean().optional(),
        cursor: z.string().optional(),
        backgroundColor: z.string().optional(),
      }).optional(),
      timelines: z.array(z.record(z.unknown())).optional(),
    });

    const parsed = schema.parse(data);

    const experiment = new Experiment('deserialized', {
      metadata: parsed.metadata,
      ...parsed.options,
    });

    // Note: Timeline deserialization would need to be handled by a registry
    // This is a simplified implementation

    return experiment;
  }
}

