import { Device, DeviceCapabilities } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface AudioDeviceInfo {
  deviceId: string;
  label: string;
  kind: MediaDeviceKind;
  groupId: string;
}

export interface AudioEventData {
  level?: number;
  frequency?: number;
  duration?: number;
  buffer?: ArrayBuffer;
}

export class AudioDevice extends Device {
  private audioContext?: AudioContext;
  private mediaStream?: MediaStream;
  private analyser?: AnalyserNode;
  private microphone?: MediaStreamAudioSourceNode;
  private outputNode?: AudioDestinationNode;
  private isRecording: boolean = false;
  private deviceChangeHandler: () => void;
  private monitoringFrameId?: number;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      maxSampleRate: 48000,
      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
    };

    super('audio-primary', 'audio', capabilities, clock);

    // Bind event handler to maintain correct reference for removal
    this.deviceChangeHandler = this.handleDeviceChange.bind(this);
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    try {
      // Create audio context
      this.audioContext = new (window.AudioContext ||
        (window as any).webkitAudioContext)();

      // Resume context if suspended (required for some browsers)
      if (this.audioContext.state === 'suspended') {
        await this.audioContext.resume();
      }

      this.outputNode = this.audioContext.destination;
      this.setConnected(true);

      // Monitor device changes
      navigator.mediaDevices?.addEventListener(
        'devicechange',
        this.deviceChangeHandler,
      );
    } catch (error) {
      throw new Error(`Failed to initialize audio device: ${error}`);
    }
  }

  async cleanup(): Promise<void> {
    await this.stopRecording();

    // Cancel any pending animation frames
    if (this.monitoringFrameId) {
      cancelAnimationFrame(this.monitoringFrameId);
      this.monitoringFrameId = undefined;
    }

    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach((track) => track.stop());
      this.mediaStream = undefined;
    }

    // Properly disconnect audio nodes before closing context
    if (this.microphone) {
      this.microphone.disconnect();
      this.microphone = undefined;
    }

    if (this.analyser) {
      this.analyser.disconnect();
      this.analyser = undefined;
    }

    if (this.audioContext) {
      await this.audioContext.close();
      this.audioContext = undefined;
    }

    // Remove event listener using correct reference

